using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;

namespace ContosoUniversity.Tests.Controllers;

public class StudentsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly StudentsController _controller;

    public StudentsControllerTests()
    {
        _context = TestDbContextFactory.Create();
        _controller = new StudentsController(_context);
        // Set up TempData for controller
        _controller.TempData = new TempDataDictionary(
            new DefaultHttpContext(), 
            new SessionStateTempDataProvider(new SessionStateTempDataProviderOptions()));
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private Student CreateTestStudent(string lastName = "Smith", string firstName = "John", DateTime? enrollmentDate = null)
    {
        return new Student
        {
            LastName = lastName,
            FirstMidName = firstName,
            EnrollmentDate = enrollmentDate ?? new DateTime(2023, 9, 1)
        };
    }

    private void SeedStudents(params Student[] students)
    {
        _context.Students.AddRange(students);
        _context.SaveChanges();
    }

    #region Index Tests

    [Fact]
    public void Index_NoParameters_ReturnsViewWithAllStudents()
    {
        // Arrange
        SeedStudents(
            CreateTestStudent("Adams", "Alice"),
            CreateTestStudent("Baker", "Bob"));

        // Act
        var result = _controller.Index(null, null, null, null) as ViewResult;

        // Assert
        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal(2, model.Count);
    }

    [Fact]
    public void Index_SortByNameDesc_ReturnsSortedStudents()
    {
        // Arrange
        SeedStudents(
            CreateTestStudent("Adams", "Alice"),
            CreateTestStudent("Zimmerman", "Zoe"));

        // Act
        var result = _controller.Index("name_desc", null, null, null) as ViewResult;

        // Assert
        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal("Zimmerman", model[0].LastName);
        Assert.Equal("Adams", model[1].LastName);
    }

    [Fact]
    public void Index_SortByDate_ReturnsSortedByEnrollmentDate()
    {
        // Arrange
        SeedStudents(
            CreateTestStudent("Adams", "Alice", new DateTime(2024, 1, 1)),
            CreateTestStudent("Baker", "Bob", new DateTime(2022, 1, 1)));

        // Act
        var result = _controller.Index("Date", null, null, null) as ViewResult;

        // Assert
        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal("Baker", model[0].LastName);
        Assert.Equal("Adams", model[1].LastName);
    }

    [Fact]
    public void Index_SortByDateDesc_ReturnsSortedDescending()
    {
        // Arrange
        SeedStudents(
            CreateTestStudent("Adams", "Alice", new DateTime(2022, 1, 1)),
            CreateTestStudent("Baker", "Bob", new DateTime(2024, 1, 1)));

        // Act
        var result = _controller.Index("date_desc", null, null, null) as ViewResult;

        // Assert
        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal("Baker", model[0].LastName);
    }

    [Fact]
    public void Index_SearchByLastName_FiltersResults()
    {
        // Arrange
        SeedStudents(
            CreateTestStudent("Adams", "Alice"),
            CreateTestStudent("Baker", "Bob"));

        // Act
        var result = _controller.Index(null, null, "Adams", null) as ViewResult;

        // Assert
        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Single(model);
        Assert.Equal("Adams", model[0].LastName);
    }

    [Fact]
    public void Index_SearchByFirstName_FiltersResults()
    {
        // Arrange
        SeedStudents(
            CreateTestStudent("Adams", "Alice"),
            CreateTestStudent("Baker", "Bob"));

        // Act
        var result = _controller.Index(null, null, "Bob", null) as ViewResult;

        // Assert
        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Single(model);
        Assert.Equal("Baker", model[0].LastName);
    }

    [Fact]
    public void Index_WithNewSearch_ResetsPageTo1()
    {
        // Arrange
        SeedStudents(CreateTestStudent("Adams", "Alice"));

        // Act
        var result = _controller.Index(null, null, "Adams", 3) as ViewResult;

        // Assert
        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal(1, model.PageIndex);
    }

    [Fact]
    public void Index_WithCurrentFilter_UsesExistingFilter()
    {
        // Arrange
        SeedStudents(
            CreateTestStudent("Adams", "Alice"),
            CreateTestStudent("Baker", "Bob"));

        // Act
        var result = _controller.Index(null, "Adams", null, 1) as ViewResult;

        // Assert
        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Single(model);
    }

    [Fact]
    public void Index_SetsViewBagSortParameters()
    {
        // Act
        var result = _controller.Index(null, null, null, null) as ViewResult;

        // Assert
        Assert.NotNull(result);
        Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
        Assert.Equal("Date", _controller.ViewBag.DateSortParm);
    }

    [Fact]
    public void Index_WithNameDescSort_SetsNameSortToEmpty()
    {
        // Act
        _controller.Index("name_desc", null, null, null);

        // Assert
        Assert.Equal("", _controller.ViewBag.NameSortParm);
    }

    #endregion

    #region Details Tests

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_ValidId_ReturnsViewWithStudent()
    {
        // Arrange
        var student = CreateTestStudent();
        student.Enrollments = new List<Enrollment>();
        _context.Students.Add(student);
        _context.SaveChanges();

        // Act
        var result = _controller.Details(student.ID) as ViewResult;

        // Assert
        Assert.NotNull(result);
        var model = Assert.IsType<Student>(result.Model);
        Assert.Equal("Smith", model.LastName);
    }

    #endregion

    #region Create Tests

    [Fact]
    public void Create_Get_ReturnsViewWithDefaultEnrollmentDate()
    {
        // Act
        var result = _controller.Create() as ViewResult;

        // Assert
        Assert.NotNull(result);
        var model = Assert.IsType<Student>(result.Model);
        Assert.Equal(DateTime.Today, model.EnrollmentDate);
    }

    [Fact]
    public void Create_ValidStudent_RedirectsToIndex()
    {
        // Arrange
        var student = CreateTestStudent();

        // Act
        var result = _controller.Create(student);

        // Assert
        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
        Assert.Single(_context.Students);
    }

    [Fact]
    public void Create_InvalidEnrollmentDate_ReturnsViewWithModelError()
    {
        // Arrange
        var student = CreateTestStudent(enrollmentDate: DateTime.MinValue);

        // Act
        var result = _controller.Create(student) as ViewResult;

        // Assert
        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [Fact]
    public void Create_EnrollmentDateOutOfRange_ReturnsViewWithModelError()
    {
        // Arrange
        var student = CreateTestStudent(enrollmentDate: new DateTime(1000, 1, 1));

        // Act
        var result = _controller.Create(student) as ViewResult;

        // Assert
        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    [Fact]
    public void Create_InvalidModelState_ReturnsView()
    {
        // Arrange
        var student = CreateTestStudent();
        _controller.ModelState.AddModelError("LastName", "Required");

        // Act
        var result = _controller.Create(student) as ViewResult;

        // Assert
        Assert.NotNull(result);
        Assert.Equal(student, result.Model);
    }

    #endregion

    #region Edit Tests

    [Fact]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Edit((int?)null);

        // Assert
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Edit_Get_NotFound_ReturnsNotFound()
    {
        // Act
        var result = _controller.Edit(999);

        // Assert
        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Edit_Get_ValidId_ReturnsViewWithStudent()
    {
        // Arrange
        var student = CreateTestStudent();
        _context.Students.Add(student);
        _context.SaveChanges();

        // Act
        var result = _controller.Edit(student.ID) as ViewResult;

        // Assert
        Assert.NotNull(result);
        Assert.IsType<Student>(result.Model);
    }

    [Fact]
    public void Edit_Post_ValidStudent_RedirectsToIndex()
    {
        // Arrange
        var student = CreateTestStudent();
        _context.Students.Add(student);
        _context.SaveChanges();
        _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var updatedStudent = new Student
        {
            ID = student.ID,
            LastName = "Updated",
            FirstMidName = "Name",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        // Act
        var result = _controller.Edit(updatedStudent);

        // Assert
        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
    }

    [Fact]
    public void Edit_Post_InvalidEnrollmentDate_ReturnsView()
    {
        // Arrange
        var student = new Student
        {
            ID = 1,
            LastName = "Smith",
            FirstMidName = "John",
            EnrollmentDate = DateTime.MinValue
        };

        // Act
        var result = _controller.Edit(student) as ViewResult;

        // Assert
        Assert.NotNull(result);
        Assert.True(_controller.ModelState.ContainsKey("EnrollmentDate"));
    }

    #endregion

    #region Delete Tests

    [Fact]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Delete(null);

        // Assert
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Delete_Get_NotFound_ReturnsNotFound()
    {
        // Act
        var result = _controller.Delete(999);

        // Assert
        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Delete_Get_ValidId_ReturnsViewWithStudent()
    {
        // Arrange
        var student = CreateTestStudent();
        _context.Students.Add(student);
        _context.SaveChanges();

        // Act
        var result = _controller.Delete(student.ID) as ViewResult;

        // Assert
        Assert.NotNull(result);
        Assert.IsType<Student>(result.Model);
    }

    [Fact]
    public void DeleteConfirmed_ValidId_RemovesStudentAndRedirects()
    {
        // Arrange
        var student = CreateTestStudent();
        _context.Students.Add(student);
        _context.SaveChanges();

        // Act
        var result = _controller.DeleteConfirmed(student.ID);

        // Assert
        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
        Assert.Empty(_context.Students);
    }

    #endregion
}

