using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.Extensions.Logging;
using Moq;

namespace ContosoUniversity.Tests.Controllers;

public class CoursesControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly CoursesController _controller;
    private readonly Mock<IWebHostEnvironment> _mockEnv;
    private readonly Mock<ILogger<CoursesController>> _mockLogger;

    public CoursesControllerTests()
    {
        _context = TestDbContextFactory.Create();
        _mockEnv = new Mock<IWebHostEnvironment>();
        _mockEnv.Setup(e => e.WebRootPath).Returns("/wwwroot");
        _mockEnv.Setup(e => e.ContentRootPath).Returns("/content");
        _mockLogger = new Mock<ILogger<CoursesController>>();
        _controller = new CoursesController(_context, _mockEnv.Object, _mockLogger.Object);
        _controller.TempData = new TempDataDictionary(
            new DefaultHttpContext(),
            new SessionStateTempDataProvider(new SessionStateTempDataProviderOptions()));
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private Department CreateTestDepartment(string name = "Engineering")
    {
        var dept = new Department
        {
            Name = name,
            Budget = 100000m,
            StartDate = new DateTime(2020, 1, 1)
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();
        return dept;
    }

    private Course CreateTestCourse(int courseId = 1001, string title = "Calculus", int credits = 3, int? departmentId = null)
    {
        if (departmentId == null)
        {
            var dept = CreateTestDepartment();
            departmentId = dept.DepartmentID;
        }
        return new Course
        {
            CourseID = courseId,
            Title = title,
            Credits = credits,
            DepartmentID = departmentId.Value
        };
    }

    #region Index Tests

    [Fact]
    public void Index_ReturnsViewWithAllCourses()
    {
        // Arrange
        var dept = CreateTestDepartment();
        _context.Courses.Add(new Course { CourseID = 1001, Title = "Calc", Credits = 3, DepartmentID = dept.DepartmentID });
        _context.Courses.Add(new Course { CourseID = 1002, Title = "Physics", Credits = 4, DepartmentID = dept.DepartmentID });
        _context.SaveChanges();

        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        Assert.NotNull(result);
        var model = Assert.IsAssignableFrom<List<Course>>(result.Model);
        Assert.Equal(2, model.Count);
    }

    [Fact]
    public void Index_EmptyDatabase_ReturnsEmptyList()
    {
        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        Assert.NotNull(result);
        var model = Assert.IsAssignableFrom<List<Course>>(result.Model);
        Assert.Empty(model);
    }

