        _context.Courses.Add(course);
        _context.SaveChanges();
        _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var updated = new Course { CourseID = 4002, Title = "Advanced Music", Credits = 3, DepartmentID = dept.DepartmentID };

        // Act
        var result = _controller.Edit(updated, null!);

        // Assert
        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
    }

    [Fact]
    public void Edit_Post_InvalidImageExtension_ReturnsViewWithError()
    {
        // Arrange
        var dept = CreateTestDepartment();
        var course = new Course { CourseID = 4003, Title = "Art", Credits = 2, DepartmentID = dept.DepartmentID };
        _context.Courses.Add(course);
        _context.SaveChanges();
