using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;

namespace ContosoUniversity.Tests.Controllers;

public class InstructorsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly InstructorsController _controller;

    public InstructorsControllerTests()
    {
        _context = TestDbContextFactory.Create();
        _controller = new InstructorsController(_context);
        _controller.TempData = new TempDataDictionary(
            new DefaultHttpContext(),
            new SessionStateTempDataProvider(new SessionStateTempDataProviderOptions()));
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    private Instructor CreateTestInstructor(string lastName = "Fakhouri", string firstName = "Fadi", DateTime? hireDate = null)
    {
        var instructor = new Instructor
        {
            LastName = lastName,
            FirstMidName = firstName,
            HireDate = hireDate ?? new DateTime(2020, 3, 15),
            CourseAssignments = new List<CourseAssignment>()
        };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();
        return instructor;
    }

    private Course CreateTestCourse(int courseId, string title = "Test Course")
    {
        var dept = new Department
        {
            Name = "TestDept",
            Budget = 10000m,
            StartDate = new DateTime(2020, 1, 1)
        };
        _context.Departments.Add(dept);
        _context.SaveChanges();

        var course = new Course
        {
            CourseID = courseId,
            Title = title,
            Credits = 3,
            DepartmentID = dept.DepartmentID,
            Enrollments = new List<Enrollment>(),
            CourseAssignments = new List<CourseAssignment>()
        };
        _context.Courses.Add(course);
        _context.SaveChanges();
        return course;
    }

    #region Index Tests

    [Fact]
    public void Index_NoParameters_ReturnsViewWithInstructors()
    {
        // Arrange
        var instructor = CreateTestInstructor();

        // Act
        var result = _controller.Index(null, null) as ViewResult;

        // Assert
        Assert.NotNull(result);
        var model = Assert.IsType<Models.SchoolViewModels.InstructorIndexData>(result.Model);
        Assert.Single(model.Instructors);
    }

    [Fact]
    public void Index_WithInstructorId_PopulatesCourses()
    {
        // Arrange
        var course = CreateTestCourse(6001, "Algorithms");
        var instructor = new Instructor
        {
            LastName = "Smith",
            FirstMidName = "John",
            HireDate = new DateTime(2020, 1, 1),
            CourseAssignments = new List<CourseAssignment>
            {
                new CourseAssignment { CourseID = course.CourseID }
            }
        };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        // Act
        var result = _controller.Index(instructor.ID, null) as ViewResult;

        // Assert
        Assert.NotNull(result);
        var model = Assert.IsType<Models.SchoolViewModels.InstructorIndexData>(result.Model);
        Assert.NotNull(model.Courses);
        Assert.Single(model.Courses);
    }

    [Fact]
    public void Index_EmptyDatabase_ReturnsEmptyList()
    {
        // Act
        var result = _controller.Index(null, null) as ViewResult;

        // Assert
        Assert.NotNull(result);
        var model = Assert.IsType<Models.SchoolViewModels.InstructorIndexData>(result.Model);
        Assert.Empty(model.Instructors);
    }

    #endregion

    #region Details Tests

    [Fact]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Act
        var result = _controller.Details(null);

        // Assert
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_NotFound_ReturnsNotFound()
    {
        // Act
        var result = _controller.Details(999);

        // Assert
        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Details_ValidId_ReturnsViewWithInstructor()
    {
        // Arrange
        var instructor = CreateTestInstructor("Kapoor", "Candace");

        // Act
        var result = _controller.Details(instructor.ID) as ViewResult;

        // Assert
        Assert.NotNull(result);
        var model = Assert.IsType<Instructor>(result.Model);
        Assert.Equal("Kapoor", model.LastName);
    }

    #endregion

    #region Create Tests

    [Fact]
    public void Create_Get_ReturnsViewWithCourseData()
    {
        // Arrange
        CreateTestCourse(7001, "Data Structures");

        // Act
        var result = _controller.Create() as ViewResult;

        // Assert
        Assert.NotNull(result);
        Assert.NotNull(_controller.ViewBag.Courses);
    }

    [Fact]
    public void Create_Post_ValidInstructor_RedirectsToIndex()
    {
        // Arrange
        var instructor = new Instructor
        {
            LastName = "Newman",
            FirstMidName = "Roger",
            HireDate = new DateTime(2023, 8, 1),
            CourseAssignments = new List<CourseAssignment>()
        };

        // Act
        var result = _controller.Create(instructor, null!);

        // Assert
