using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests.Services;

public class NotificationServiceTests : IDisposable
{
    private readonly NotificationService _service;

    public NotificationServiceTests()
    {
        _service = new NotificationService();
        // Drain any residual notifications from other tests (static queue)
        while (_service.ReceiveNotification() != null) { }
    }

    public void Dispose()
    {
        _service.Dispose();
    }

    #region SendNotification Tests

    [Fact]
    public void SendNotification_WithDisplayName_CreatesCorrectMessage()
    {
        // Act
        _service.SendNotification("Student", "1", "John Smith", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("1", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Contains("John Smith", notification.Message);
        Assert.Contains("created", notification.Message);
        Assert.Equal("Admin", notification.CreatedBy);
        Assert.False(notification.IsRead);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        // Act
        _service.SendNotification("Course", "42", EntityOperation.UPDATE, "System");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("ID: 42", notification.Message);
        Assert.Contains("updated", notification.Message);
    }

    [Fact]
    public void SendNotification_NullUserName_DefaultsToSystem()
    {
        // Act
        _service.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE, null);

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("System", notification.CreatedBy);
    }

    [Theory]
    [InlineData(EntityOperation.CREATE, "created")]
    [InlineData(EntityOperation.UPDATE, "updated")]
    [InlineData(EntityOperation.DELETE, "deleted")]
    public void SendNotification_AllOperations_GeneratesCorrectMessages(EntityOperation operation, string expectedVerb)
    {
        // Act
        _service.SendNotification("Entity", "1", "TestEntity", operation, "User");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains(expectedVerb, notification.Message);
    }

    [Fact]
    public void SendNotification_SetsCreatedAtToCurrentTime()
    {
        // Arrange
        var before = DateTime.Now.AddSeconds(-1);

        // Act
        _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE, "User");

        // Assert
        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.True(notification.CreatedAt >= before);
        Assert.True(notification.CreatedAt <= DateTime.Now.AddSeconds(1));
    }

    #endregion

    #region ReceiveNotification Tests

    [Fact]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        // Act
        var result = _service.ReceiveNotification();

        // Assert
        Assert.Null(result);
    }

    [Fact]
    public void ReceiveNotification_MultipleMessages_ReturnsInFIFOOrder()
    {
        // Arrange
        _service.SendNotification("First", "1", "First", EntityOperation.CREATE, "User");
        _service.SendNotification("Second", "2", "Second", EntityOperation.UPDATE, "User");

        // Act & Assert
        var first = _service.ReceiveNotification();
        Assert.NotNull(first);
        Assert.Equal("First", first.EntityType);

        var second = _service.ReceiveNotification();
        Assert.NotNull(second);
        Assert.Equal("Second", second.EntityType);
    }

    [Fact]
    public void ReceiveNotification_AfterReceive_MessageIsDequeued()
    {
        // Arrange
        _service.SendNotification("Test", "1", "Test", EntityOperation.CREATE, "User");

        // Act
        _service.ReceiveNotification();
        var second = _service.ReceiveNotification();

        // Assert
        Assert.Null(second);
    }

    #endregion

    #region MarkAsRead Tests

    [Fact]
    public void MarkAsRead_DoesNotThrow()
    {
        // Act & Assert (no-op for in-memory, should not throw)
        var ex = Record.Exception(() => _service.MarkAsRead(1));
        Assert.Null(ex);
    }

    [Fact]
    public void MarkAsRead_WithAnyId_CompletesSuccessfully()
    {
        // Act & Assert
        var ex = Record.Exception(() => _service.MarkAsRead(999));
        Assert.Null(ex);
    }

    #endregion

    #region Dispose Tests

    [Fact]
    public void Dispose_MultipleCalls_DoesNotThrow()
    {
        // Act & Assert
        var service = new NotificationService();
        var ex = Record.Exception(() =>
        {
            service.Dispose();
            service.Dispose();
        });
        Assert.Null(ex);
    }

    #endregion

    #region Queue Capacity Tests

    [Fact]
    public void SendNotification_ExceedingMaxCapacity_DropsOldestMessages()
    {
        // Arrange: Fill queue beyond max (500 per implementation)
        for (int i = 0; i < 510; i++)
        {
            _service.SendNotification("Bulk", i.ToString(), $"Item{i}", EntityOperation.CREATE, "User");
        }

        // Act: Drain the queue and count
        int count = 0;
        while (_service.ReceiveNotification() != null)
        {
            count++;
        }

        // Assert: Should be capped at max (500)
        Assert.True(count <= 500);
    }

    #endregion
}

