using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Helpers;

public class PaginatedListTests
{
    private IQueryable<int> CreateTestQueryable(int count)
    {
        return Enumerable.Range(1, count).AsQueryable();
    }

    [Fact]
    public void Create_FirstPage_ReturnsCorrectItems()
    {
        // Arrange
        var source = CreateTestQueryable(25);

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.Equal(10, result.Count);
        Assert.Equal(1, result.PageIndex);
        Assert.Equal(3, result.TotalPages);
    }

    [Fact]
    public void Create_MiddlePage_ReturnsCorrectItems()
    {
        // Arrange
        var source = CreateTestQueryable(25);

        // Act
        var result = PaginatedList<int>.Create(source, 2, 10);

        // Assert
        Assert.Equal(10, result.Count);
        Assert.Equal(11, result[0]);
        Assert.Equal(2, result.PageIndex);
    }

    [Fact]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        // Arrange
        var source = CreateTestQueryable(25);

        // Act
        var result = PaginatedList<int>.Create(source, 3, 10);

        // Assert
        Assert.Equal(5, result.Count);
        Assert.Equal(21, result[0]);
    }

    [Fact]
    public void HasPreviousPage_FirstPage_ReturnsFalse()
    {
        // Arrange
        var source = CreateTestQueryable(25);

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.False(result.HasPreviousPage);
    }

    [Fact]
    public void HasPreviousPage_SecondPage_ReturnsTrue()
    {
        // Arrange
        var source = CreateTestQueryable(25);

        // Act
        var result = PaginatedList<int>.Create(source, 2, 10);

        // Assert
        Assert.True(result.HasPreviousPage);
    }

    [Fact]
    public void HasNextPage_LastPage_ReturnsFalse()
    {
        // Arrange
        var source = CreateTestQueryable(25);

        // Act
        var result = PaginatedList<int>.Create(source, 3, 10);

        // Assert
        Assert.False(result.HasNextPage);
    }

    [Fact]
    public void HasNextPage_FirstPage_ReturnsTrue()
    {
        // Arrange
        var source = CreateTestQueryable(25);

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.True(result.HasNextPage);
    }

    [Fact]
    public void TotalPages_ExactlyDivisible_ReturnsCorrectCount()
    {
        // Arrange
        var source = CreateTestQueryable(20);

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.Equal(2, result.TotalPages);
    }

    [Fact]
    public void TotalPages_SingleItem_ReturnsOne()
    {
        // Arrange
        var source = CreateTestQueryable(1);

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.Equal(1, result.TotalPages);
        Assert.Single(result);
    }

    [Fact]
    public void TotalPages_EmptySource_ReturnsZero()
    {
        // Arrange
        var source = Enumerable.Empty<int>().AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 10);

        // Assert
        Assert.Equal(0, result.TotalPages);
        Assert.Empty(result);
    }

    [Theory]
    [InlineData(1, 5, 1)]
    [InlineData(6, 5, 2)]
    [InlineData(10, 5, 2)]
    [InlineData(11, 5, 3)]
    public void TotalPages_VariousCounts_CalculatesCorrectly(int itemCount, int pageSize, int expectedPages)
    {
        // Arrange
        var source = CreateTestQueryable(itemCount);

        // Act
        var result = PaginatedList<int>.Create(source, 1, pageSize);

        // Assert
        Assert.Equal(expectedPages, result.TotalPages);
    }

    [Fact]
    public void Constructor_SetsPropertiesCorrectly()
    {
        // Arrange
        var items = new List<string> { "a", "b", "c" };

        // Act
        var result = new PaginatedList<string>(items, 10, 2, 5);

        // Assert
        Assert.Equal(2, result.PageIndex);
        Assert.Equal(2, result.TotalPages);
        Assert.Equal(3, result.Count);
        Assert.Contains("a", result);
    }
}

