[Fact]
public void DeleteConfirmed_InstructorIsDepartmentAdmin_ClearsDepartmentAdmin()
{
    // Arrange
    var instructor = CreateTestInstructor("Admin", "Dept");
    var dept = new Department
    {
        Name = "TestDept",
        Budget = 50000m,
        StartDate = new DateTime(2020, 1, 1),
        InstructorID = instructor.ID
    };
    _context.Departments.Add(dept);
    _context.SaveChanges();

    // Act
    _controller.DeleteConfirmed(instructor.ID);

    // Assert
    var updatedDept = _context.Departments.Find(dept.DepartmentID);
    Assert.Null(updatedDept!.InstructorID);
}

#endregion

#region Edit GET Tests

[Fact]
public void Edit_Get_NullId_ReturnsBadRequest()
{
    // Act
    var result = _controller.Edit((int?)null);

    // Assert
    var statusResult = Assert.IsType<StatusCodeResult>(result);
    Assert.Equal(400, statusResult.StatusCode);
}

[Fact]
public void Edit_Get_ValidId_ReturnsViewWithInstructorAndCourseData()
{
    // Arrange
    var course = CreateTestCourse(8001, "Operating Systems");
    var instructor = new Instructor
    {
        LastName = "Wilson",
        FirstMidName = "Mark",
        HireDate = new DateTime(2019, 6, 1),
        CourseAssignments = new List<CourseAssignment>
        {
            new CourseAssignment { CourseID = course.CourseID }
        }
    };
    _context.Instructors.Add(instructor);
    _context.SaveChanges();

    // Act
    var result = _controller.Edit(instructor.ID) as ViewResult;

    // Assert
    Assert.NotNull(result);
    var model = Assert.IsType<Instructor>(result.Model);
    Assert.Equal("Wilson", model.LastName);
    Assert.NotNull(_controller.ViewBag.Courses);
}

#endregion

#region Edit POST Tests

[Fact]
public async Task Edit_Post_NullId_ReturnsBadRequest()
{
    // Arrange
    SetupControllerContext();

    // Act
    var result = await _controller.Edit(null, null!);

    // Assert
    var statusResult = Assert.IsType<StatusCodeResult>(result);
    Assert.Equal(400, statusResult.StatusCode);
}

private void SetupControllerContext()
{
    var httpContext = new DefaultHttpContext();
    _controller.ControllerContext = new ControllerContext
    {
        HttpContext = httpContext,
        RouteData = new RouteData()
    };
}

#endregion

