[Fact]
public void SendNotification_SetsCreatedAtToCurrentTime()
{
    // Drain stale messages
    while (_service.ReceiveNotification() != null) { }

    // Arrange
    var before = DateTime.Now.AddSeconds(-1);

    // Act
    _service.SendNotification("Student", "1", "Test", EntityOperation.CREATE, "User");

    // Assert
    var notification = _service.ReceiveNotification();
    Assert.NotNull(notification);
    Assert.True(notification.CreatedAt >= before);
    Assert.True(notification.CreatedAt <= DateTime.Now.AddSeconds(1));
}

