[Fact]
public void Create_Post_ValidImageUpload_SavesFileAndRedirects()
{
    // Arrange
    var tempDir = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
    Directory.CreateDirectory(tempDir);
    _mockEnv.Setup(e => e.WebRootPath).Returns(tempDir);

    try
    {
        var dept = CreateTestDepartment();
        var course = new Course { CourseID = 3010, Title = "Art History", Credits = 3, DepartmentID = dept.DepartmentID };
        var content = new byte[] { 0x89, 0x50, 0x4E, 0x47 }; // PNG header bytes
        var mockFile = new Mock<IFormFile>();
        mockFile.Setup(f => f.FileName).Returns("material.png");
        mockFile.Setup(f => f.Length).Returns(content.Length);
        mockFile.Setup(f => f.CopyTo(It.IsAny<Stream>())).Callback<Stream>(s => s.Write(content, 0, content.Length));

        // Act
        var result = _controller.Create(course, mockFile.Object);

        // Assert
        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
        var savedCourse = _context.Courses.Find(3010);
        Assert.NotNull(savedCourse);
        Assert.StartsWith("/Uploads/TeachingMaterials/", savedCourse.TeachingMaterialImagePath);
    }
    finally
    {
        Directory.Delete(tempDir, true);
    }
}

