using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

public class NotificationsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly NotificationsController _controller;

    public NotificationsControllerTests()
    {
        _context = TestDbContextFactory.Create();
        _controller = new NotificationsController(_context);
        _controller.SetupTempData();
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [Fact]
    public void GetNotifications_EmptyQueue_ReturnsSuccessWithEmptyList()
    {
        // Drain the static queue
        var svc = new NotificationService();
        while (svc.ReceiveNotification() != null) { }

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.NotNull(result);
        var json = Assert.IsType<JsonResult>(result);
        Assert.NotNull(json.Value);
        // Verify it has success = true via reflection on anonymous type
        var successProp = json.Value.GetType().GetProperty("success");
        Assert.NotNull(successProp);
        Assert.True((bool)successProp.GetValue(json.Value)!);
    }

    [Fact]
    public void GetNotifications_WithQueuedMessages_ReturnsNotifications()
    {
        // Arrange: send some notifications via service
        var svc = new NotificationService();
        // Drain first
        while (svc.ReceiveNotification() != null) { }
        svc.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE, "Admin");
        svc.SendNotification("Course", "2", "Test Course", EntityOperation.UPDATE, "User");

        // Act
        var result = _controller.GetNotifications();

        // Assert
        var json = Assert.IsType<JsonResult>(result);
        Assert.NotNull(json.Value);
        var countProp = json.Value.GetType().GetProperty("count");
        Assert.NotNull(countProp);
        var count = (int)countProp.GetValue(json.Value)!;
        Assert.True(count >= 1);
    }

    [Fact]
    public void GetNotifications_LimitsTen_DoesNotExceedMax()
    {
        // Arrange: queue more than 10 messages
        var svc = new NotificationService();
        while (svc.ReceiveNotification() != null) { }
        for (int i = 0; i < 15; i++)
        {
            svc.SendNotification("Entity", i.ToString(), $"Item{i}", EntityOperation.CREATE, "User");
        }

        // Act
        var result = _controller.GetNotifications();

        // Assert
        var json = Assert.IsType<JsonResult>(result);
        var countProp = json.Value!.GetType().GetProperty("count");
        var count = (int)countProp!.GetValue(json.Value)!;
        Assert.True(count <= 10);
    }

    [Fact]
    public void MarkAsRead_ValidId_ReturnsSuccessJson()
    {
        // Act
        var result = _controller.MarkAsRead(1);

        // Assert
        Assert.NotNull(result);
        var json = Assert.IsType<JsonResult>(result);
        var successProp = json.Value!.GetType().GetProperty("success");
        Assert.True((bool)successProp!.GetValue(json.Value)!);
    }

    [Fact]
    public void MarkAsRead_AnyId_ReturnsSuccess()
    {
        // Act
        var result = _controller.MarkAsRead(999);

        // Assert
        var json = Assert.IsType<JsonResult>(result);
        var successProp = json.Value!.GetType().GetProperty("success");
        Assert.True((bool)successProp!.GetValue(json.Value)!);
    }

    [Fact]
    public void Index_ReturnsViewResult()
    {
        // Act
        var result = _controller.Index() as ViewResult;

        // Assert
        Assert.NotNull(result);
    }
}

